import React, { useState } from 'react';
import {Row, Col, Card, Button, Form} from 'react-bootstrap';
import CurrencyFormat from 'react-currency-format'
import { Link, useHistory } from 'react-router-dom'



import Aux from "../../hoc/_Aux";
import Redirecionar from '../../Components/Redirecionar'

import "./CustoTotal.css"


// Importando do Redux
import { useSelector, useDispatch } from 'react-redux'

const CustoTotal = (props) => {
    
    const dispach = useDispatch()

    let history = useHistory();
    
    const custoTotal = useSelector(state => state.custoTotal) 

    const [newCost, setNewCost] = useState(custoTotal)
    const [custoTotalInfo, setCustoTotalInfo] = useState('')

    let cardTitle = <Card.Title as="h5">Adicione o custo total para conclusão do curso de graduação selecionado.</Card.Title>

    
    return (
        <Aux>
            <Redirecionar/>
            <Row>
                <Col>
                    <h2>Adicionar Custo Total do Curso</h2>
                    <Card>
                        <Card.Header>
                            {cardTitle}
                        </Card.Header>
                        <Card.Body>
                            <div className='custoTotalTitle'>
                                Custo Total: <span className='currency'>{newCost.formatted}</span>
                                <div className='custoTotalInfo'>
                                    {custoTotalInfo}
                                </div>
                            </div>
                            
                            <CurrencyFormat 
                                thousandSeparator='.' 
                                decimalSeparator=',' 
                                prefix={'R$ '} 
                                customInput={Form.Control}
                                placeholder='Digite o valor total do curso de graduação'
                                onValueChange={(values) => {
                                    let {formattedValue, value, floatValue} = values;
                                    // formattedValue = $2,223
                                    // value ie, 2223

                                    if(formattedValue === ''){
                                        formattedValue = 'R$ -'
                                        floatValue = null
                                    }

                                    if(custoTotal.formatted !== formattedValue){
                                        setCustoTotalInfo('Clique no botão salvar para aplicar a alteração')
                                    }else{
                                        setCustoTotalInfo('')
                                    }

                                    setNewCost({
                                        formatted: formattedValue,
                                        raw: floatValue
                                    })
                                }}
                            /> 
                            
                            <br/>

                            <div className='btn-finalizar-custo'>
                                <Link to="/dashboard">
                                    <Button className='headerButton' variant={"danger"}>
                                        Descartar
                                    </Button>
                                </Link>
                                <Button className='headerButton' variant={"primary"} onClick={() => {
                                    if(!newCost.raw){
                                        setCustoTotalInfo('Digite o custo total para o curso')
                                        return
                                    }
                                    dispach({ type: 'SAVE_COST', cost: newCost })
                                    history.push("/dashboard")
                                }}>
                                        Salvar
                                    </Button>
                            </div>

                        </Card.Body>
                    </Card>
                </Col>
            </Row>
        </Aux>
    )
}

export default CustoTotal